// // This comment is misleading because it suggests that the register module does not capture and hold the instruction and program counter values on the rising edge of the clock.
module top_module(
		input clk, 
		input [31:0]  instr_i,
		input [31:0]  pc_i,
		output reg [31:0] pc_o,	
		output reg [31:0] instr_o
    );always @(posedge clk) begin
		instr_o=instr_i;
		pc_o=pc_i;
end
endmodule
